    cards: [
      { id: 1100, front: "hydrALAZINE vs hydrOXYzine", back: "HydrALAZINE: antihypertensive (vasodilator). HydrOXYzine: antihistamine/anxiolytic. Very different indications and effects.", difficulty: 1 },
      { id: 1101, front: "predniSONE vs prednisoLONE", back: "PredniSONE: inactive prodrug, must be converted by liver. PrednisoLONE: active form, preferred in liver disease.", difficulty: 2 },
      { id: 1102, front: "vinCRIStine vs vinBLAStine", back: "Both are vinca alkaloid chemo drugs but with VERY different dosing. VinCRIStine intrathecally = universally fatal. Must label 'FOR IV USE ONLY.'", difficulty: 3 },
      { id: 1103, front: "DOBUTamine vs DOPamine", back: "DOBUTamine: inotrope (increases contractility). DOPamine: dose-dependent effects on dopaminergic, beta-1, and alpha receptors.", difficulty: 2 },
      { id: 1104, front: "buPROPion vs busPIRone", back: "BuPROPion: NDRI antidepressant/smoking cessation. BusPIRone: 5-HT1A agonist anxiolytic (non-benzo).", difficulty: 2 },
      { id: 1105, front: "celeXA vs celeBREX", back: "CeleXA (citalopram): SSRI antidepressant. CeleBREX (celecoxib): COX-2 selective NSAID.", difficulty: 2 },
      { id: 1106, front: "clomiPHENE vs clomiPRAMINE", back: "ClomiPHENE: fertility drug (ovulation induction). ClomiPRAMINE: TCA antidepressant for OCD.", difficulty: 3 },
      { id: 1107, front: "DAUNOrubicin vs DOXOrubicin", back: "Both are anthracycline chemo agents but with different dosing, indications, and liposomal formulations.", difficulty: 3 },
      { id: 1108, front: "glipiZIDE vs glyBURIDE", back: "Both are sulfonylureas but different potency and duration. GlyBURIDE is more potent; glipiZIDE is shorter-acting.", difficulty: 2 },
      { id: 1109, front: "hydrOCODone vs OXYcodone", back: "Both opioid analgesics, both C-II. OXYcodone is approximately 1.5× more potent than hydrOCODone.", difficulty: 2 },
      { id: 1110, front: "lamiVUDine vs lamoTRIgine", back: "LamiVUDine: antiviral (HIV/HBV). LamoTRIgine: antiepileptic/mood stabilizer for bipolar.", difficulty: 2 },
      { id: 1111, front: "metFORMIN vs metroNIDAZOLE", back: "MetFORMIN: biguanide for type 2 diabetes. MetroNIDAZOLE: antibiotic/antiprotozoal (Flagyl).", difficulty: 1 },
      { id: 1112, front: "OLANZapine vs QUEtiapine", back: "Both atypical antipsychotics but different side effect profiles. OLANZapine causes more weight gain.", difficulty: 2 },
      { id: 1113, front: "risperiDONE vs rOPINIRole", back: "RisperiDONE: atypical antipsychotic. ROPINIRole: dopamine agonist for Parkinson's disease.", difficulty: 2 },
      { id: 1114, front: "SUFentanil vs FENTanyl vs ALFentanil", back: "All synthetic opioids. SUFentanil: 5-10× more potent than FENTanyl. ALFentanil: shorter acting than FENTanyl.", difficulty: 3 },
      { id: 1115, front: "traMADol vs traZODone", back: "TraMADol: centrally acting analgesic (C-IV). TraZODone: antidepressant, commonly used for insomnia.", difficulty: 1 },
      { id: 1116, front: "Zantac vs Zyrtec vs Zyprexa", back: "Zantac (ranitidine): H2 blocker. Zyrtec (cetirizine): antihistamine. Zyprexa (olanzapine): antipsychotic.", difficulty: 2 },
      { id: 1117, front: "EPINEPHrine vs ePHEDrine", back: "EPINEPHrine: first-line for anaphylaxis/cardiac arrest. EPHEDrine: vasopressor, pseudoephedrine precursor.", difficulty: 2 },
      { id: 1118, front: "Humalog vs Humulin", back: "Humalog (lispro): rapid-acting insulin. Humulin R (regular): short-acting. Humulin N (NPH): intermediate-acting.", difficulty: 2 },
      { id: 1119, front: "Losartan vs Lisinopril", back: "Losartan: ARB (-sartan). Lisinopril: ACE inhibitor (-pril). Different classes but both for hypertension.", difficulty: 1 },
    ],
