    description: "DEA requirements for ordering, storing, dispensing, and disposing of controlled substances",
    category: "Regulations/Law",
    cards: [
      { id: 1200, front: "Schedule I examples", back: "Heroin, LSD, ecstasy (MDMA), peyote, marijuana (federal). No accepted medical use, high abuse potential.", difficulty: 1 },
      { id: 1201, front: "Schedule II examples", back: "Oxycodone, morphine, fentanyl, amphetamine, methylphenidate, methadone, hydromorphone, cocaine (medical)", difficulty: 1 },
      { id: 1202, front: "Schedule III examples", back: "Testosterone, anabolic steroids, ketamine, buprenorphine products, codeine combinations", difficulty: 2 },
      { id: 1203, front: "Schedule IV examples", back: "Alprazolam, diazepam, zolpidem, tramadol, carisoprodol, modafinil", difficulty: 2 },
      { id: 1204, front: "Schedule V examples", back: "Pregabalin, lacosamide, cough preparations with limited codeine (some states)", difficulty: 2 },
      { id: 1205, front: "How to order C-II drugs?", back: "DEA Form 222 (triplicate) or electronic CSOS (Controlled Substance Ordering System)", difficulty: 2 },
      { id: 1206, front: "C-II storage requirements?", back: "Locked cabinet or dispersed throughout non-controlled stock to obstruct theft. Many states require locked storage.", difficulty: 2 },
      { id: 1207, front: "Partial fill of C-II: time limit?", back: "Must complete within 72 hours for regular patients. LTCF/terminally ill: up to 60 days.", difficulty: 3 },
      { id: 1208, front: "Can C-II prescriptions be faxed?", back: "Faxes serve as original for: home infusion, LTCF, and hospice patients. Otherwise fax is 'courtesy copy' — original must be presented.", difficulty: 3 },
      { id: 1209, front: "C-II emergency dispensing rules?", back: "Pharmacist may dispense limited quantity for emergency. Prescriber must provide written/electronic Rx within 7 days.", difficulty: 3 },
      { id: 1210, front: "How to destroy controlled substances?", back: "DEA Form 41 with witnessed destruction by authorized reverse distributor or DEA-sanctioned event", difficulty: 2 },
      { id: 1211, front: "What to do if controlled substances are stolen?", back: "File DEA Form 106 immediately. Notify local law enforcement. Document all details of the loss.", difficulty: 2 },
      { id: 1212, front: "Biennial inventory requirements?", back: "Complete inventory every 2 years. C-II: exact count required. C-III to C-V: estimated count unless container has ≤1,000 dosage units.", difficulty: 2 },
      { id: 1213, front: "Can a C-II prescription be transferred?", back: "No. Schedule II prescriptions cannot be transferred between pharmacies.", difficulty: 1 },
      { id: 1214, front: "What is drug diversion?", back: "Unauthorized transfer of controlled substances from legitimate channels to unauthorized individuals. A serious federal offense.", difficulty: 1 },
      { id: 1215, front: "Signs of drug diversion?", back: "Missing medications, altered records, frequent 'broken vials,' unusual controlled substance usage patterns, behavioral changes", difficulty: 2 },
      { id: 1216, front: "Who can prescribe controlled substances?", back: "Licensed prescribers (MDs, DOs, NPs, PAs, dentists, podiatrists, veterinarians) with valid DEA registration", difficulty: 1 },
      { id: 1217, front: "EPCS requirements?", back: "Electronic Prescribing for Controlled Substances requires DEA-certified software, identity proofing, and two-factor authentication", difficulty: 3 },
      { id: 1218, front: "Tramadol schedule?", back: "Schedule IV (since 2014). Lower abuse potential than C-II opioids. Some states schedule it more restrictively.", difficulty: 2 },
      { id: 1219, front: "Perpetual inventory for C-II?", back: "Continuous real-time record of all receipts, dispensing, waste, and returns. Allows quick discrepancy identification.", difficulty: 2 },
    ],
