export function getPharmacyTechDecks(): FlashcardDeck[] {
  return pharmacyTechDecks;
}

export function getPharmacyTechDeckById(id: string): FlashcardDeck | undefined {
  return pharmacyTechDecks.find(d => d.id === id);
}

export function getTotalFlashcardCount(): number {
  return pharmacyTechDecks.reduce((sum, deck) => sum + deck.cards.length, 0);
}
